import os

def simplify_path(path: str) -> str:
    parts = path.split('/')
    stack = []
    is_absolute = path.startswith('/')

    for part in parts:
        if part == '' or part == '.':
            continue
        elif part == '..':
            if stack:
                stack.pop()
            elif not is_absolute:
                stack.append('..')
        else:
            stack.append(part)

    if not stack:
        return '/' if is_absolute else '.'

    result = '/'.join(stack)
    if is_absolute:
        result = '/' + result
    return result
